import { useEffect, useState, useContext } from "react";
import { AuthContext } from "./AuthContext";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [events, setEvents] = useState([]);
    const [clubs, setClubs] = useState([]);
    const [users, setUsers] = useState([]); // for leader dropdown

    const [windowWidth, setWindowWidth] = useState(window.innerWidth);
    const { user } = useContext(AuthContext);

    // Thread modal state
    const [showThreadModal, setShowThreadModal] = useState(false);
    const [newThread, setNewThread] = useState({ title: "", content: "" });

    // News modal state
    const [showNewsModal, setShowNewsModal] = useState(false);
    const [newNews, setNewNews] = useState({ title: "", content: "" });
    // #region agent log
    useEffect(() => {
        fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:20',message:'Modal state initialized',data:{showThreadModal,showNewsModal},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{});
    }, [showThreadModal, showNewsModal]);
    // #endregion

    // Club modal state
    const [showClubModal, setShowClubModal] = useState(false);
    const [newClub, setNewClub] = useState({ name: "", description: "", leaderUserId: "" });
    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads).catch(() => setThreads([]));
        fetch("/api/news").then(res => res.json()).then(setNews).catch(() => setNews([]));
        fetch("/api/events").then(res => res.json()).then(setEvents).catch(() => setEvents([]));
        fetch("/api/clubs").then(res => res.json()).then(data => {
            setClubs(Array.isArray(data) ? data : []);
        }).catch(() => setClubs([]));

        // preload users for leader dropdown (admins only)
        if (isAdmin) {
            fetch("/api/users").then(r => r.json()).then(setUsers).catch(() => setUsers([]));
        }

        function handleResize() { setWindowWidth(window.innerWidth); }
        window.addEventListener("resize", handleResize);
        return () => window.removeEventListener("resize", handleResize);
    }, [isAdmin]);

    const hideThreads = windowWidth < 1000;
    const hideEvents = windowWidth < 800;

    const newsWidth = hideThreads ? (hideEvents ? "70%" : "50%") : "40%";
    const clubsWidth = hideThreads ? (hideEvents ? "30%" : "25%") : "20%";
    const threadsWidth = "20%";
    const eventsWidth = hideThreads ? "25%" : "20%";

    const headNews = news.length > 0 ? news[0] : null;
    const otherNews = news.length > 1 ? news.slice(1) : [];

    // Thread modal handlers
    const handleThreadChange = (e) => {
        const { name, value } = e.target;
        setNewThread(prev => ({ ...prev, [name]: value }));
    };

    const handleThreadSubmit = async (e) => {
        e.preventDefault();
        try {
            const res = await fetch("/api/threads", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(newThread),
            });
            const savedThread = await res.json();
            if (!res.ok) {
                alert(savedThread.message || "Failed to create thread");
                return;
            }
            setThreads(prev => [savedThread, ...prev]);
            setNewThread({ title: "", content: "" });
            setShowThreadModal(false);
        } catch (err) {
            console.error("Failed to save thread", err);
            alert("Failed to save thread");
        }
    };

    // Request to join a club
    const requestJoin = async (clubId, e) => {
        e.stopPropagation(); // prevent navigating when clicking the button
        if (!user) {
            alert("Please log in to request to join.");
            return;
        }
        try {
            const res = await fetch(`/api/clubs/${clubId}/join?requesterEmail=${encodeURIComponent(user.email)}`, {
                method: "POST"
            });
            const body = await res.json().catch(() => ({}));
            if (!res.ok) {
                alert(body.message || "Failed to send request");
                return;
            }
            alert("Join request sent!");
        } catch (err) {
            alert("Failed to send request");
        }
    };

    // Club modal handlers
    const openClubModal = () => {
        setNewClub({ name: "", description: "", leaderUserId: "" });
        setShowClubModal(true);
        // Ensure users list is fresh (in case admin opened later)
        if (isAdmin && users.length === 0) {
            fetch("/api/users").then(r => r.json()).then(setUsers).catch(() => setUsers([]));
        }
    };

    const handleClubChange = (e) => {
        const { name, value } = e.target;
        setNewClub(prev => ({ ...prev, [name]: value }));
    };

    const handleClubSubmit = async (e) => {
        e.preventDefault();
        if (!isAdmin) return;
        if (!newClub.name.trim() || !newClub.description.trim()) {
            alert("Please fill club name and description.");
            return;
        }
        if (!newClub.leaderUserId) {
            if (!window.confirm("No leader selected. Create club without a leader?")) return;
        }
        try {
            // 1) Create club
            const createRes = await fetch(`/api/clubs?requesterEmail=${encodeURIComponent(user.email)}`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ name: newClub.name.trim(), description: newClub.description.trim() })
            });
            const created = await createRes.json().catch(() => ({}));
            if (!createRes.ok) {
                alert(created.message || "Failed to create club");
                return;
            }

            // 2) Optionally assign leader
            if (newClub.leaderUserId) {
                const assignRes = await fetch(`/api/clubs/${created.id}/leader?requesterEmail=${encodeURIComponent(user.email)}`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ userId: Number(newClub.leaderUserId) })
                });
                const assignBody = await assignRes.json().catch(() => ({}));
                if (!assignRes.ok) {
                    alert(assignBody.message || "Club created, but assigning leader failed");
                    // We still proceed to add the club to UI
                }
            }

            // 3) Update UI and close
            setClubs(prev => [...prev, created]);
            setShowClubModal(false);
            setNewClub({ name: "", description: "", leaderUserId: "" });

            // 4) (Optional) Navigate to club page
            // window.location.hash = `#/clubs/${created.id}`;
        } catch (err) {
            console.error(err);
            alert("Failed to create club");
        }
    };


    // News modal handlers
    const handleNewsChange = (e) => {
        const { name, value } = e.target;
        setNewNews(prev => ({ ...prev, [name]: value }));
    };

    const handleNewsSubmit = async (e) => {
        e.preventDefault();
        try {
            const res = await fetch("/api/news", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(newNews),
            });
            const savedNews = await res.json();
            if (!res.ok) {
                alert(savedNews.message || "Failed to create News");
                return;
            }
            setNews(prev => [savedNews, ...prev]);
            // #region agent log
            fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:192',message:'Resetting newNews',data:{resetValue:{title:"",content:""},expectedValue:{headline:"",body:""},newNewsBefore:newNews},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
            // #endregion
            setNewNews({ title: "", content: "" });
            setShowNewsModal(false);
        } catch (err) {
            console.error("Failed to save news", err);
            alert("Failed to save news");
        }
    };

    return (
        <main style={styles.Dashboard}>
            <div style={styles.container}>
                <div style={styles.flexRow}>
                    {!hideThreads && (
                        <div style={styles.section}>
                            <h3 style={styles.sectionTitle}>
                                <span>💬</span> Threads
                            </h3>
                            {isAdmin && (
                                <button 
                                    style={styles.addBtn} 
                                    onClick={() => setShowThreadModal(true)}
                                    onMouseEnter={(e) => { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 6px 16px rgba(4, 30, 66, 0.4)"; }}
                                    onMouseLeave={(e) => { e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "0 4px 12px rgba(4, 30, 66, 0.3)"; }}
                                >
                                    ➕ Add Thread
                                </button>
                            )}
                            {threads.length > 0 ? threads.map((thread, idx) => (
                                <div
                                    style={styles.Threads}
                                    key={idx}
                                    onClick={() => { window.location.hash = `#/thread/${thread.id}`; }}
                                    onMouseEnter={(e) => { e.target.style.transform = "translateX(4px)"; e.target.style.boxShadow = "0 4px 16px rgba(0,0,0,0.12)"; e.target.style.borderLeftColor = "#041E42"; }}
                                    onMouseLeave={(e) => { e.target.style.transform = "translateX(0)"; e.target.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)"; e.target.style.borderLeftColor = "#041E42"; }}
                                >
                                    <span style={{ fontWeight: "500", color: "#333" }}>{thread.title}</span>
                                </div>
                            )) : (
                                <div style={styles.emptyState}>No threads yet</div>
                            )}
                        </div>
                    )}
                    {/* News */}
                    <div style={{ ...styles.section, flex: hideThreads ? (hideEvents ? "1 1 60%" : "1 1 50%") : "1 1 40%" }}>
                        <h3 style={styles.sectionTitle}>
                            <span>📰</span> News
                        </h3>
                        {isAdmin && (
                            <button 
                                style={styles.addBtn} 
                                onClick={() => {
                                    // #region agent log
                                    fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:226',message:'Add News button clicked',data:{showNewsModalBefore:showNewsModal},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{});
                                    // #endregion
                                    setShowNewsModal(true);
                                    // #region agent log
                                    setTimeout(() => fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:228',message:'After setShowNewsModel(true)',data:{showNewsModalAfter:showNewsModal},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{}), 10);
                                    // #endregion
                                }}
                                onMouseEnter={(e) => { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 6px 16px rgba(4, 30, 66, 0.4)"; }}
                                onMouseLeave={(e) => { e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "0 4px 12px rgba(4, 30, 66, 0.3)"; }}
                            >
                                ➕ Add News
                            </button>
                        )}
                        {headNews && (
                            <div
                                style={styles.HeadNews}
                                onClick={() => {
                                    // #region agent log
                                    fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:231',message:'Head news clicked',data:{newsId:news?.id,headNewsId:headNews?.id,newsLength:news?.length},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'B'})}).catch(()=>{});
                                    // #endregion
                                    window.location.hash = `#/news/${headNews.id}`;
                                }}
                                onMouseEnter={(e) => { e.target.style.transform = "translateY(-4px)"; e.target.style.boxShadow = "0 12px 32px rgba(0,0,0,0.2)"; }}
                                onMouseLeave={(e) => { e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "0 8px 24px rgba(0,0,0,0.15)"; }}
                            >
                                {headNews.imageUrl && <img src={headNews.imageUrl} alt={headNews.title} style={styles.HeadNewsImage} />}
                                <div style={styles.HeadNewsOverlay}>
                                    <h4 style={{ margin: 0, fontSize: "20px" }}>{headNews.title}</h4>
                                </div>
                            </div>
                        )}
                        {otherNews.map((item, idx) => (
                            <div
                                key={idx}
                                onClick={() => {
                                    // #region agent log
                                    fetch('http://127.0.0.1:7242/ingest/eca2c071-a6e9-463e-b837-0f74ac8dbf00',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Dashboard.js:242',message:'Other news clicked',data:{itemId:item?.id,newsId:news?.id,newsLength:news?.length},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'B'})}).catch(()=>{});
                                    // #endregion
                                    window.location.hash = `#/news/${item.id}`;
                                }}
                                style={styles.News}
                                onMouseEnter={(e) => { e.target.style.transform = "translateX(4px)"; e.target.style.boxShadow = "0 4px 16px rgba(0,0,0,0.12)"; e.target.style.borderLeftColor = "#D50032"; }}
                                onMouseLeave={(e) => { e.target.style.transform = "translateX(0)"; e.target.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)"; e.target.style.borderLeftColor = "#D50032"; }}
                            >
                                <span style={{ fontWeight: "500", color: "#333" }}>{item.title}</span>
                            </div>
                        ))}
                        {news.length === 0 && (
                            <div style={styles.emptyState}>No news yet</div>
                        )}
                    </div>

                    {/* Clubs */}
                    <div style={{ ...styles.section, flex: hideThreads ? (hideEvents ? "1 1 30%" : "1 1 25%") : "1 1 20%" }}>
                        <h3 style={styles.sectionTitle}>
                            <span>🏛️</span> Clubs
                        </h3>
                        {isAdmin && (
                            <button 
                                style={styles.addBtn} 
                                onClick={openClubModal}
                                onMouseEnter={(e) => { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 6px 16px rgba(4, 30, 66, 0.4)"; }}
                                onMouseLeave={(e) => { e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "0 4px 12px rgba(4, 30, 66, 0.3)"; }}
                            >
                                ➕ Add Club
                            </button>
                        )}
                        {clubs.length > 0 ? clubs.map((club) => (
                            <div
                                key={club.id}
                                onClick={() => { window.location.hash = `#/clubs/${club.id}`; }}
                                style={styles.Clubs}
                                title={`Open ${club.name}`}
                                onMouseEnter={(e) => { e.target.style.transform = "translateX(4px)"; e.target.style.boxShadow = "0 4px 16px rgba(0,0,0,0.12)"; e.target.style.borderLeftColor = "#0b57d0"; }}
                                onMouseLeave={(e) => { e.target.style.transform = "translateX(0)"; e.target.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)"; e.target.style.borderLeftColor = "#0b57d0"; }}
                            >
                                <div style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", fontWeight: "500", color: "#333" }}>
                                    {club.name}
                                </div>
                            </div>
                        )) : (
                            <div style={styles.emptyState}>No clubs yet</div>
                        )}
                    </div>

                    {/* Events */}
                    {!hideEvents && (
                        <div style={{ ...styles.section, flex: hideThreads ? "1 1 25%" : "1 1 20%" }}>
                            <h3 style={styles.sectionTitle}>
                                <span>📅</span> Events
                            </h3>
                            {isAdmin && (
                                <button 
                                    style={styles.addBtn} 
                                    onClick={() => { window.location.hash = "#/events"; }}
                                    onMouseEnter={(e) => { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 6px 16px rgba(4, 30, 66, 0.4)"; }}
                                    onMouseLeave={(e) => { e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "0 4px 12px rgba(4, 30, 66, 0.3)"; }}
                                >
                                    ➕ Add Event
                                </button>
                            )}
                            {events.length > 0 ? events.map((event, idx) => (
                                <div
                                    key={idx}
                                    onClick={() => alert(`Clicked event: ${event.name}`)}
                                    style={styles.Events}
                                    onMouseEnter={(e) => { e.target.style.transform = "translateX(4px)"; e.target.style.boxShadow = "0 4px 16px rgba(0,0,0,0.12)"; e.target.style.borderLeftColor = "#10b981"; }}
                                    onMouseLeave={(e) => { e.target.style.transform = "translateX(0)"; e.target.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)"; e.target.style.borderLeftColor = "#10b981"; }}
                                >
                                    <div style={{ fontWeight: "500", color: "#333", marginBottom: "4px" }}>{event.name}</div>
                                    <small style={{ color: "#666", fontSize: "13px" }}>{new Date(event.event_date_time).toLocaleString()}</small>
                                </div>
                            )) : (
                                <div style={styles.emptyState}>No events yet</div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Thread Modal */}
            {showThreadModal && (
                <div style={styles.ThreadWindow}>
                    <div style={styles.ThreadContent}>
                        <h3>Add New Thread</h3>
                        <form onSubmit={handleThreadSubmit}>
                            <input
                                name="title"
                                placeholder="Thread Title"
                                value={newThread.title}
                                onChange={handleThreadChange}
                                required
                                style={styles.input}
                            />
                            <textarea
                                name="content"
                                placeholder="Thread Content"
                                value={newThread.content}
                                onChange={handleThreadChange}
                                required
                                style={styles.textarea}
                            />
                            <button type="submit" style={styles.submitBtn}>Save Thread</button>
                            <button type="button" onClick={() => setShowThreadModal(false)} style={styles.cancelBtn}>Cancel</button>
                        </form>
                    </div>
                </div>
            )}

            {/* News Modal */}
            {showNewsModal && (
                <div style={styles.ThreadWindow}>
                    <div style={styles.ThreadContent}>
                        <h3>Add New News</h3>
                        <form onSubmit={handleNewsSubmit}>
                            <input
                                name="title"
                                placeholder="News Title"
                                value={newNews.title}
                                onChange={handleNewsChange}
                                required
                                style={styles.input}
                            />
                            <textarea
                                name="content"
                                placeholder="News Content"
                                value={newNews.content}
                                onChange={handleNewsChange}
                                required
                                style={styles.textarea}
                            />
                            <button type="submit" style={styles.submitBtn}>Save News</button>
                            <button type="button" onClick={() => setShowNewsModal(false)} style={styles.cancelBtn}>Cancel</button>
                        </form>
                    </div>
                </div>
            )}

            {/* Club Modal (ADMIN) */}
            {showClubModal && (
                <div style={styles.ThreadWindow}>
                    <div style={styles.ThreadContent}>
                        <h3>Create Club</h3>
                        <form onSubmit={handleClubSubmit}>
                            <input
                                name="name"
                                placeholder="Club Name"
                                value={newClub.name}
                                onChange={handleClubChange}
                                required
                                style={styles.input}
                            />
                            <textarea
                                name="description"
                                placeholder="Description"
                                value={newClub.description}
                                onChange={handleClubChange}
                                required
                                style={styles.textarea}
                            />
                            <select
                                name="leaderUserId"
                                value={newClub.leaderUserId}
                                onChange={handleClubChange}
                                style={styles.input}
                            >
                                <option value="">(Optional) Select Leader</option>
                                {users.map(u => (
                                    <option key={u.id} value={u.id}>
                                        {u.username} — {u.email}
                                    </option>
                                ))}
                            </select>

                            <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
                                <button type="button" onClick={() => setShowClubModal(false)} style={styles.cancelBtn}>Cancel</button>
                                <button type="submit" style={styles.submitBtn}>Create</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

        </main>
    );
}

const boxBase = {
    border: "none",
    padding: "16px",
    marginBottom: "12px",
    borderRadius: "12px",
    cursor: "pointer",
    minHeight: "60px",
    display: "flex",
    alignItems: "center",
    backgroundColor: "#ffffff",
    transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
    boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
    borderLeft: "4px solid transparent",
};

const styles = {
    Dashboard: { 
        paddingTop: "70px", 
        minHeight: "100vh", 
        background: "linear-gradient(135deg, #f5f7fa 0%, #e8ecf1 100%)",
        paddingBottom: "40px"
    },
    container: { 
        maxWidth: "1400px", 
        margin: "0 auto", 
        padding: "30px 20px"
    },
    flexRow: { 
        display: "flex", 
        gap: "24px", 
        flexWrap: "wrap"
    },
    section: {
        flex: "1 1 300px",
        minWidth: "280px",
        backgroundColor: "#ffffff",
        borderRadius: "16px",
        padding: "24px",
        boxShadow: "0 4px 20px rgba(0,0,0,0.08)",
        border: "1px solid rgba(0,0,0,0.05)",
    },
    sectionTitle: {
        fontSize: "22px",
        fontWeight: "700",
        color: "#041E42",
        marginBottom: "20px",
        paddingBottom: "12px",
        borderBottom: "2px solid #f0f0f0",
        display: "flex",
        alignItems: "center",
        gap: "10px"
    },
    Threads: { 
        ...boxBase,
        borderLeftColor: "#041E42",
    },
    News: { 
        ...boxBase,
        borderLeftColor: "#D50032",
    },
    Clubs: { 
        ...boxBase,
        borderLeftColor: "#0b57d0",
        justifyContent: "space-between"
    },
    Events: { 
        ...boxBase,
        borderLeftColor: "#10b981",
    },
    HeadNews: { 
        position: "relative", 
        width: "100%", 
        height: "200px", 
        marginBottom: "20px", 
        borderRadius: "16px", 
        overflow: "hidden", 
        boxShadow: "0 8px 24px rgba(0,0,0,0.15)", 
        cursor: "pointer",
        transition: "transform 0.3s ease, box-shadow 0.3s ease"
    },
    HeadNewsImage: { 
        width: "100%", 
        height: "100%", 
        objectFit: "cover",
        transition: "transform 0.3s ease"
    },
    HeadNewsOverlay: { 
        position: "absolute", 
        bottom: 0, 
        left: 0, 
        right: 0, 
        background: "linear-gradient(to top, rgba(0,0,0,0.8) 0%, rgba(0,0,0,0.4) 50%, transparent 100%)", 
        color: "#fff", 
        padding: "20px", 
        fontSize: "18px",
        fontWeight: "600"
    },
    addBtn: { 
        margin: "0 0 20px 0", 
        padding: "10px 20px", 
        fontSize: "14px", 
        borderRadius: "8px", 
        backgroundColor: "#041E42", 
        color: "#ffffff", 
        border: "none", 
        cursor: "pointer", 
        fontWeight: "600", 
        textDecoration: "none", 
        display: "inline-flex",
        alignItems: "center",
        gap: "8px",
        transition: "all 0.3s ease",
        boxShadow: "0 4px 12px rgba(4, 30, 66, 0.3)"
    },
    smallBtn: { 
        padding: "6px 12px", 
        fontSize: "13px", 
        background: "#0b57d0", 
        color: "#fff", 
        border: "none", 
        borderRadius: "6px", 
        cursor: "pointer",
        transition: "all 0.3s ease"
    },
    ThreadWindow: { 
        position: "fixed", 
        top: 0, 
        left: 0, 
        right: 0, 
        bottom: 0, 
        backgroundColor: "rgba(0,0,0,0.6)", 
        backdropFilter: "blur(4px)",
        display: "flex", 
        justifyContent: "center", 
        alignItems: "center", 
        zIndex: 1000,
        animation: "fadeIn 0.2s ease"
    },
    ThreadContent: { 
        backgroundColor: "#fff", 
        padding: "32px", 
        borderRadius: "16px", 
        width: "500px", 
        maxWidth: "90%",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
        animation: "slideUp 0.3s ease"
    },
    modalTitle: {
        fontSize: "24px",
        fontWeight: "700",
        color: "#041E42",
        marginBottom: "24px",
        paddingBottom: "16px",
        borderBottom: "2px solid #f0f0f0"
    },
    input: { 
        width: "100%", 
        padding: "12px 16px", 
        marginBottom: "16px", 
        borderRadius: "8px", 
        border: "2px solid #e0e0e0",
        fontSize: "15px",
        transition: "all 0.3s ease",
        outline: "none",
        boxSizing: "border-box"
    },
    textarea: { 
        width: "100%", 
        padding: "12px 16px", 
        minHeight: "120px", 
        borderRadius: "8px", 
        border: "2px solid #e0e0e0", 
        marginBottom: "20px", 
        resize: "vertical",
        fontSize: "15px",
        fontFamily: "inherit",
        transition: "all 0.3s ease",
        outline: "none",
        boxSizing: "border-box"
    },
    submitBtn: { 
        padding: "12px 24px", 
        backgroundColor: "#D50032", 
        color: "#fff", 
        border: "none", 
        borderRadius: "8px", 
        cursor: "pointer",
        fontSize: "15px",
        fontWeight: "600",
        transition: "all 0.3s ease",
        boxShadow: "0 4px 12px rgba(213, 0, 50, 0.3)",
        marginRight: "12px"
    },
    cancelBtn: { 
        padding: "12px 24px", 
        backgroundColor: "#f5f5f5", 
        color: "#333", 
        border: "none", 
        borderRadius: "8px", 
        cursor: "pointer",
        fontSize: "15px",
        fontWeight: "600",
        transition: "all 0.3s ease"
    },
    emptyState: {
        textAlign: "center",
        padding: "40px 20px",
        color: "#999",
        fontSize: "14px",
        fontStyle: "italic"
    }
};

export default Dashboard;
